1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Step[];
6	};
7	
8	const PROCESSING_FEE = 5;
9	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
10	const ITEM_BASE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	};
17	
18	const COMPONENT_BLOCK_BASE = 60;
19	
20	const itemBase = (item: Item): number => ITEM_BASE[item.type];
21	
22	const calculatePolicyBase = (items: Item[]): number => {
23	  if (items.length === 3 && items.every((i) => i.type === items[0].type)) {
24	    return COMPONENT_BLOCK_BASE;
25	  }
26	  return items.reduce((sum, item) => sum + itemBase(item), 0);
27	};
28	
29	const quotePremium = ({ items }: Step): number => {
30	  const policyBase = calculatePolicyBase(items);
31	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
32	  return policyBase + firstContractSurcharge + PROCESSING_FEE;
33	};
34	
35	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
36	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
37	  return { results };
38	};
