const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_BASE = 60;

const itemBase = (item: Item): number => ITEM_BASE[item.type];

const isComponentBlock = (items: Item[]): boolean =>
  items.length === COMPONENT_BLOCK_SIZE &&
  items.every((item) => item.type === items[0].type);

const sumItemBases = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemBase(item), 0);

const calculatePolicyBase = (items: Item[]): number =>
  isComponentBlock(items) ? COMPONENT_BLOCK_BASE : sumItemBases(items);
